import {cors} from "hono/cors";
import {Hono} from "hono";
import {TodoAPI} from "./TodoAPI";

export default new Hono<{}>()
    .use(cors())

    // Mount the TODO API underneath us
    .route('/api', TodoAPI)

    // Finally - serve static assets from Vite
    .mount('/', (req, env) => env.ASSETS.fetch(req))

import { Hono } from 'hono'

const app = new Hono()

app.get('/', (c) => {
  return c.json({ message: 'Hello Bun!' })
})

const port = parseInt(process.env.PORT!) || 3000
console.log(`Running at http://localhost:${port}`)

export default {
  port,
  fetch: app.fetch,
}

// Add X-Response-Time header
app.use('*', async (c, next) => {
  const start = Date.now()
  await next()
  const ms = Date.now() - start
  c.header('X-Response-Time', `${ms}ms`)
})

// Custom Not Found Message
app.notFound((c) => {
  return c.text('Custom 404 Not Found', 404)
})

function cache(seconds: number) {
  return createMiddleware(async (c, next) => {
    if (!c.req.path.match(/\.[a-zA-Z0-9]+$/) || c.req.path.endsWith(".data")) {
      return next();
    }

    await next();

    if (!c.res.ok || c.res.headers.has("cache-control")) {
      return;
    }

    c.res.headers.set("cache-control", `public, max-age=${seconds}`);
  });
}

function serveEmojiFavicon(emoji: string): MiddlewareHandler {
  return async (c, next) => {
    if (c.req.path === '/favicon.ico') {
      c.header('Content-Type', 'image/svg+xml')
      return c.body(`<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 100 100"><text y=".9em" x="-0.1em" font-size="90">${emoji}</text></svg>`)
    }
    return next()
  }
}

import { Layout } from '../components/Layout'
