dbMiddleware = async (c: Context<Env>, next) => {
  if (c.env.DB === undefined) {
    throw new Error('DB is not defined');
  }

  if (db === null) {
    db = drizzle(c.env.DB, { logger: c.env.ENVIRONMENT !== 'production' });
  }

  c.set('db', db);

  return next();
}

remove: AppRouteHandler<RemoveRoute> = async (c) => {
  const { id } = c.req.valid("param");
  const result = await db.delete(tasks)
    .where(eq(tasks.id, id));

  if (result.rowsAffected === 0) {
    return c.json(
      {
        message: HttpStatusPhrases.NOT_FOUND,
      },
      HttpStatusCodes.NOT_FOUND,
    );
  }

  return c.body(null, HttpStatusCodes.NO_CONTENT);
}

export const getConnInfo: GetConnInfo = (c) => {
  const bindings = (c.env.server ? c.env.server : c.env) as HttpBindings

  const address = bindings.incoming.socket.remoteAddress
  const port = bindings.incoming.socket.remotePort
  const family = bindings.incoming.socket.remoteFamily

  return {
    remote: {
      address,
      port,
      addressType: family === 'IPv4' ? 'IPv4' : family === 'IPv6' ? 'IPv6' : void 0,
    },
  }
}

createSession = async (c: Context<Env>, user: User, expiresAt: Date): Promise<Session> => {
  const id = getRandomBytes(32);
  const data = {
    id,
    userId: user.id,
    createdAt: new Date(),
    updatedAt: new Date(),
    expiresAt: expiresAt,
  };
  await c.get('kv').put(`session_${id}`, JSON.stringify(data), {
    expiration: expiresAt.getTime() / 1000,
  });
  return data;
}

setCookies(_event: E, res: Response, result: APIGatewayProxyResult) {
  if (res.headers.has('set-cookie')) {
    const cookies = res.headers.getSetCookie
      ? res.headers.getSetCookie()
      : Array.from(res.headers.entries())
          .filter(([k]) => k === 'set-cookie')
          .map(([, v]) => v)

    if (Array.isArray(cookies)) {
      this.setCookiesToResult(result, cookies)
      res.headers.delete('set-cookie')
    }
  }
}

async function setCsrfCookie(c: any, maxAge?: number): Promise<void> {
  const secret = c.env?.JWT_SECRET || JWT_SECRET_FALLBACK
  const isDev = c.env?.ENVIRONMENT === 'development' || !c.env?.ENVIRONMENT
  const csrfToken = await generateCsrfToken(secret)
  const cookieMaxAge = maxAge ?? (await getJwtExpirySecondsFromDb(c.env?.DB, c.env))
  setCookie(c, 'csrf_token', csrfToken, {
    httpOnly: false,
    secure: !isDev,
    sameSite: 'Strict',
    path: '/',
    maxAge: cookieMaxAge,
  })
}

type SessionStorageEnv<Data> = Env & {
Variables: {
  sessionStorage?: Storage<Data>
}
}

type Set<E extends Env, Storage> = Storage | ((c: Context<E>) => Storage)

export const useSessionStorage = <Data, E extends SessionStorageEnv<Data>>(
set: Set<E, Storage<Data>>
): MiddlewareHandler<E> =>
createMiddleware<E>((c, next) => {
  c.set('sessionStorage', typeof set === 'function' ? set(c) : set)
  return next()
})

convertHeaders = (headers: Headers): CloudFrontHeaders => {
  const cfHeaders: CloudFrontHeaders = {}
  headers.forEach((value, key) => {
    cfHeaders[key.toLowerCase()] = [
      ...(cfHeaders[key.toLowerCase()] || []),
      { key: key.toLowerCase(), value },
    ]
  })
  return cfHeaders
}

createResult = async (res: Response): Promise<CloudFrontResult> => {
  const isBase64Encoded = isContentTypeBinary(res.headers.get('content-type') || '')
  const body = isBase64Encoded ? encodeBase64(await res.arrayBuffer()) : await res.text()

  return {
    status: res.status.toString(),
    headers: convertHeaders(res.headers),
    body,
    ...(isBase64Encoded && { bodyEncoding: 'base64' }),
  }
}

