findInsertBefore = (node: Node | undefined): SupportedElement | Text | undefined => {
  while (node && (node.tag === HONO_PORTAL_ELEMENT || !node.e)) {
    node = node.tag === HONO_PORTAL_ELEMENT || !node.vC?.[0] ? node.nN : node.vC[0]
  }
  return node?.e
}

getOAuthData: (c: Context): { claims: B2BTokenClaims; token: string } => {
  const claims = c.get('stytchB2BOAuthClaims')
  const token = c.get('stytchB2BOAuthToken')
  if (!claims || !token) {
    throw Error('No B2B OAuth data in context. Was B2B.authenticateOAuthToken called?')
  }
  return { claims, token }
}

function renderAlert(type: 'error' | 'warning', message: string): HtmlEscapedString | Promise<HtmlEscapedString> {
  const colors = {
    error: 'bg-red-50 dark:bg-red-900/20 text-red-800 dark:text-red-400 border-red-200 dark:border-red-800',
    warning: 'bg-yellow-50 dark:bg-yellow-900/20 text-yellow-800 dark:text-yellow-400 border-yellow-200 dark:border-yellow-800'
  }

  return html`
    <div class="mb-6 rounded-lg border ${colors[type]} p-4">
      <p class="text-sm">${message}</p>
    </div>
  `
}
